orage->log_message(array_merge($base, [ 'message_role' => 'user', 'message_content' => 'Generate Title', 'request_payload' => [ 'original_topic' => $validated_params['content_title'] ?? '', 'inline_keywords' => $validated_params['inline_keywords'] ?? '', 'custom_title_prompt' => $validated_params['custom_title_prompt'] ?? '', ], ])); $botLog = array_merge($base, [ 'message_role' => 'bot', 'message_content' => $generated_title, 'usage' => $result['usage'] ?? null, 'request_payload' => [ 'provider' => $provider, 'model' => $model, 'payload_sent' => [ 'messages' => [['role' => 'user', 'content' => $prompts['user_prompt'] ?? '']], 'ai_params' => $ai_params_override, 'system_instruction' => $prompts['system_instruction'] ?? '', ], ], ]); if (!empty($result['vector_search_scores'])) { $botLog['vector_search_scores'] = $result['vector_search_scores']; } $handler->log_storage->log_message($botLog); } $smart_seo_keyword_resolution = isset($validated_params['smart_seo_keyword_resolution']) && is_array($validated_params['smart_seo_keyword_resolution']) ? $validated_params['smart_seo_keyword_resolution'] : []; wp_send_json_success(array_merge([ 'new_title' => $generated_title, 'usage' => $result['usage'] ?? null, 'conversation_uuid' => $conversation_uuid, ], smart_seo_keyword_resolution_response_fields_logic($smart_seo_keyword_resolution))); } 